#nullable enable // autogenerated

using System.Collections.Generic;
using System.Linq;
using System.Xml;
using MVZ2.IO;
using MVZ2Logic;
using MVZ2Logic.Definitions;
using PVZEngine;

namespace MVZ2.Metas
{
    public class MapElementMeta
    {
        public string id;
        public XMLConditionList? unlockConditions;
        public Dictionary<string, object?> properties;
        public NamespaceID[] behaviours;

        private MapElementMeta(string id, Dictionary<string, object?> properties, NamespaceID[] behaviours)
        {
            this.id = id;
            this.properties = properties;
            this.behaviours = behaviours;
        }

        public static MapElementMeta? FromXmlNode(XmlNode node, string defaultNsp, IEnumerable<MapElementMetaTemplate> templates)
        {
            var id = node.GetAttribute("id");
            if (string.IsNullOrEmpty(id))
            {
                Log.LogError($"The {nameof(id)} of a {nameof(MapElementMeta)} is invalid.");
                return null;
            }
            XMLConditionList? unlockConditions = null;
            var unlockNode = node["unlock"];
            if (unlockNode != null)
            {
                unlockConditions = XMLConditionList.FromXmlNode(unlockNode, defaultNsp);
            }


            var behaviours = new List<NamespaceID>();
            Dictionary<string, object?> properties = new Dictionary<string, object?>();

            var templateID = node.GetAttribute("template");
            MapElementMetaTemplate? template = null;
            if (!string.IsNullOrEmpty(templateID))
            {
                template = templates.FirstOrDefault(t => t.id == templateID);
            }
            var behavioursNode = node["behaviours"];
            var propertyNode = node["properties"];
            var entityProps = propertyNode.ToPropertyDictionary(defaultNsp);
            foreach (var prop in entityProps)
            {
                var fullName = PropertyKeyHelper.ParsePropertyFullName(prop.Key, defaultNsp, LogicPropertyRegions.mapElement);
                properties.Add(fullName, prop.Value);
            }

            if (template != null)
            {
                behaviours.AddRange(template.behaviours);

                foreach (var prop in template.properties)
                {
                    if (properties.ContainsKey(prop.Key))
                        continue;
                    properties.Add(prop.Key, prop.Value);
                }
            }
            behavioursNode?.ModifyBehavioursAndProperties(behaviours, properties, LogicDefinitionTypes.MAP_ELEMENT_BEHAVIOUR, defaultNsp);

            return new MapElementMeta(id, properties, behaviours.ToArray())
            {
                unlockConditions = unlockConditions
            };
        }
    }
}
